export default function ProdutorDashboard({ user }: { user: any }) {
  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      {/* Cabeçalho */}
      <div className="md:flex md:items-center md:justify-between mb-8">
        <div className="flex-1 min-w-0">
          <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl sm:truncate">
            Painel do Produtor
          </h2>
          <p className="mt-1 text-sm text-gray-500">
            Bem-vindo de volta, {user.nome}.
          </p>
        </div>
        <div className="mt-4 flex md:mt-0 md:ml-4">
          <button className="ml-3 inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500">
            <svg className="-ml-1 mr-2 h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            Nova Safra
          </button>
        </div>
      </div>

      {/* KPIs */}
      <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4 mb-8">
        {[
          { label: "Saldo Disponível", value: "0,00 Kz", color: "bg-green-500" },
          { label: "Em Custódia", value: "0,00 Kz", color: "bg-blue-500" },
          { label: "A Liquidar", value: "0,00 Kz", color: "bg-yellow-500" },
          { label: "Receita Total", value: "0,00 Kz", color: "bg-gray-800" }
        ].map((kpi) => (
          <div key={kpi.label} className="bg-white overflow-hidden shadow rounded-lg border-l-4 border-transparent hover:border-green-500 transition-all">
            <div className="p-5">
              <div className="flex items-center">
                <div className={`flex-shrink-0 rounded-md p-3 ${kpi.color}`}>
                  {/* Placeholder Icon */}
                  <div className="h-6 w-6 text-white" />
                </div>
                <div className="ml-5 w-0 flex-1">
                  <dt className="text-sm font-medium text-gray-500 truncate">{kpi.label}</dt>
                  <dd className="text-lg font-bold text-gray-900">{kpi.value}</dd>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Tabela de Vendas */}
      <div className="bg-white shadow overflow-hidden sm:rounded-lg">
        <div className="px-6 py-5 border-b border-gray-200">
          <h3 className="text-lg leading-6 font-medium text-gray-900">Últimas Vendas</h3>
        </div>
        <div className="p-12 text-center">
          <svg className="mx-auto h-12 w-12 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
            <path vectorEffect="non-scaling-stroke" strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 13h6m-3-3v6m-9 1V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z" />
          </svg>
          <h3 className="mt-2 text-sm font-medium text-gray-900">Nenhuma venda</h3>
          <p className="mt-1 text-sm text-gray-500">Comece por publicar uma nova safra no mercado.</p>
        </div>
      </div>
    </div>
  );
}